examples.source:
.t-right  { text-align: right; }
.t-center { text-align: center; }
.t-just   { text-align: justify; }

.u { text-decoration: underline; }
.l { text-decoration: line-through; }
.w { text-decoration: underline wavy crimson; }
a  { text-decoration: none; }

.shadow {
  font-size: 1.6rem;
  font-weight: bold;
  color: #4f46e5;
  text-shadow: 2px 2px 4px rgba(0,0,0,0.4);
}
.ellipsis {
  width: 200px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  background: #f1f5f9;
}
